import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import './App.css';
import Navbar from "./components/Navbar";

// --- PARTE 2: CACHÉ MANUAL EN MEMORIA ---
const cacheBusqueda = {};

function App() {
  // Estados de Autenticación
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  // Estados de Datos
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false); // PARTE 2: Loader

  // Estados de Formulario
  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  // REFS para PARTE 2 y 3
  const abortControllerRef = useRef(null); // AbortController
  const statsRef = useRef(null); // Para IntersectionObserver

  // --- PARTE 2: CARGA ASÍNCRONA AVANZADA (Promise.all) ---
  const cargarDatos = async () => {
    setLoading(true);
    try {
      // Peticiones simultáneas
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) {
      console.error("Error en carga masiva:", error);
    } finally {
      setLoading(false);
    }
  };

  // --- PARTE 6: POLLING INTELIGENTE (Tiempo Real) ---
  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(() => {
        console.log("Actualizando datos en segundo plano...");
        cargarDatos();
      }, 30000); // Cada 30 segundos
      return () => clearInterval(interval);
    }
  }, [isLoggedIn]);

  // --- PARTE 3.1: INTERSECTION OBSERVER (Animación al Scroll) ---
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            entry.target.classList.add('reveal-visible');
          }
        });
      },
      { threshold: 0.1 }
    );

    if (statsRef.current) observer.observe(statsRef.current);
    return () => observer.disconnect();
  }, [view, isLoggedIn]);

  // --- PARTE 2: DEBOUNCE Y ABORTCONTROLLER ---
  const debounceSearch = useCallback((fn, delay) => {
    let timeout;
    return (...args) => {
      clearTimeout(timeout);
      timeout = setTimeout(() => fn(...args), delay);
    };
  }, []);

  const ejecutarBusqueda = async (texto) => {
    if (texto.trim() === '') {
      cargarDatos();
      return;
    }

    // Manejo de Caché
    if (cacheBusqueda[texto]) {
      setProductos(cacheBusqueda[texto]);
      return;
    }

    // Cancelar petición anterior si existe
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();

    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/buscar?q=${texto}`,
        { signal: abortControllerRef.current.signal }
      );
      cacheBusqueda[texto] = res.data; // Guardar en caché
      setProductos(res.data);
    } catch (err) {
      if (err.name !== 'CanceledError') console.error(err);
    }
  };

  const optimizadaBusqueda = useCallback(debounceSearch(ejecutarBusqueda, 500), []);

  const handleBusquedaChange = (e) => {
    const valor = e.target.value;
    setBusqueda(valor);
    optimizadaBusqueda(valor);
  };

  // --- OPERACIONES CRUD ---
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol);
      }
    } catch (e) { alert("Error de login"); }
  };

  const guardarProducto = async () => {
    const data = {
      nombre: nuevoProd.nombre,
      categoria: "General",
      stock: Number(nuevoProd.stock),
      precio_compra: 0,
      precio_venta: Number(nuevoProd.precio_venta),
      fecha_caducidad: null
    };

    if (editMode) {
      await axios.put(`http://localhost:5000/api/productos/${selectedId}`, data);
    } else {
      await axios.post('http://localhost:5000/api/productos', data);
    }

    setShowForm(false);
    setEditMode(false);
    setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    // Limpiar caché para forzar actualización
    Object.keys(cacheBusqueda).forEach(key => delete cacheBusqueda[key]);
    cargarDatos();
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // VISTA LOGIN
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card reveal-visible">
          <h2>{isRegisterMode ? 'Crear Cuenta' : 'Iniciar Sesión'}</h2>
          <input placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
          <input type="password" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
          {isRegisterMode && (
            <select onChange={e => setNuevoRol(e.target.value)}>
              <option value="vendedor">Vendedor</option>
              <option value="admin">Administrador</option>
            </select>
          )}
          <button onClick={isRegisterMode ? () => {} : handleLogin}>
            {isRegisterMode ? 'Registrarse' : 'Entrar'}
          </button>
          <p onClick={() => setIsRegisterMode(!isRegisterMode)} style={{ cursor: 'pointer' }}>
            {isRegisterMode ? 'Ya tengo cuenta' : 'Crear cuenta'}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="main-wrapper">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} />

      {loading && <div className="loader-line">Cargando...</div>}

      <main className="content-area">
        {view === "dashboard" ? (
          <div className="dashboard-grid" ref={statsRef}>
            {/* PARTE 3.3: Efecto Hover en Cards */}
            <div className="card reveal-fade">
              <h3>⚠️ Bajo Stock</h3>
              <p className="stat-number">{stats.bajo_stock}</p>
            </div>
            <div className="card reveal-fade delay-1">
              <h3>📊 Total Productos</h3>
              <p className="stat-number">{stats.total_productos}</p>
            </div>
            <div className="card reveal-fade delay-2">
              <h3>💰 Valor Inventario</h3>
              <p className="stat-number">${stats.valor_inventario}</p>
            </div>
          </div>
        ) : (
          <div className="card">
            <div className="controls">
                <button className="btn-add" onClick={() => { setShowForm(!showForm); setEditMode(false); }}>
                    {showForm ? 'Cerrar' : '+ Nuevo Producto'}
                </button>
                <input
                    type="text"
                    placeholder="Buscar con debounce..."
                    value={busqueda}
                    onChange={handleBusquedaChange}
                    className="search-input"
                />
            </div>

            {/* PARTE 3.2: Mostrar/Ocultar con transición suave (Sin display:none) */}
            <div className={`form-container ${showForm ? 'is-visible' : ''}`}>
                <input placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({ ...nuevoProd, nombre: e.target.value })} />
                <input placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({ ...nuevoProd, stock: e.target.value })} />
                <input placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({ ...nuevoProd, precio_venta: e.target.value })} />
                <button onClick={guardarProducto} className="btn-save">Guardar</button>
            </div>

            <div className="table-container">
                <table>
                <thead>
                    <tr><th>Producto</th><th>Stock</th><th>Precio</th><th>Acciones</th></tr>
                </thead>
                <tbody>
                    {productos.map(p => (
                    <tr key={p.id} className="row-animation">
                        <td>{p.nombre}</td>
                        <td>{p.stock}</td>
                        <td>${p.precio_venta}</td>
                        <td>
                        <button onClick={() => { setSelectedId(p.id); setNuevoProd(p); setEditMode(true); setShowForm(true); }}>✏️</button>
                        <button onClick={() => eliminar(p.id)}>🗑️</button>
                        </td>
                    </tr>
                    ))}
                </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
